template.template_css:
@page { size: letter landscape; }

/* Column widths */
table.vt th:nth-child(1), table.vt td:nth-child(1) { width: 160px; }
table.vt th:nth-child(2), table.vt td:nth-child(2) { width: 160px; }
table.vt th:nth-child(3), table.vt td:nth-child(3) { min-width: 180px; }
table.vt th:nth-child(4), table.vt td:nth-child(4) { width: 140px; }
table.vt th:nth-child(5), table.vt td:nth-child(5) { min-width: 200px; }
table.vt th:nth-child(6), table.vt td:nth-child(6) { width: 100px; text-align: center; }
table.vt th:nth-child(7), table.vt td:nth-child(7) { min-width: 150px; }

template.template_md:
{% block header_title %}<h1>Low RAM Agents Report</h1>
<div class="row-count" style="font-size:13px; opacity:0.85;">
    Filtered: <strong><span id="visibleCount">0</span></strong>
    of <span id="totalCount">0</span> agents
</div>{% endblock %}

{% block content %}
<div id="loading">Loading...</div>

<div class="table-wrap" id="tableWrap" style="display:none">
    <table class="vt" id="agentTable">
        <thead id="tableHead"></thead>
        <tbody id="tableBody"></tbody>
    </table>
</div>

<script id="data-json" type="application/json">
[
{% for item in data_sources.agents %}
  {
    "client": {{ (item.site__client__name if item.site__client__name else 'N/A') | tojson }},
    "site": {{ (item.site__name if item.site__name else 'N/A') | tojson }},
    "device": {{ (item.hostname if item.hostname else 'N/A') | tojson }},
    "user": {{ (item.last_logged_in_user if item.last_logged_in_user else 'N/A') | tojson }},
    "os": {{ (item.operating_system | replace(",", "") if item.operating_system else 'N/A') | tojson }},
    "ram": {{ item.total_ram | default(0) | tojson }},
    "hdd": {{ item.disks | tojson }}
  }{{ ',' if not loop.last else '' }}
{% endfor %}
]
</script>

<script>
var columns = [
    { id: 'client', title: 'Client', filter: true, selectable: true, sortable: true },
    { id: 'site', title: 'Site', filter: true, selectable: true, sortable: true },
    { id: 'device', title: 'Device Name', filter: true, selectable: true, sortable: true },
    { id: 'user', title: 'User', filter: true, selectable: false, sortable: true },
    { id: 'os', title: 'Operating System', filter: true, selectable: true, sortable: true },
    { id: 'ram', title: 'RAM (GB)', filter: true, range: true, sortable: true, numeric: true },
    { id: 'hdd', title: 'HDD', filter: false, sortable: false }
];

var data = JSON.parse(document.getElementById('data-json').textContent || '[]');

for (var i = 0; i < data.length; i++) {
    var ramVal = data[i].ram;
    data[i].ramNum = (ramVal != null && !isNaN(parseFloat(ramVal))) ? parseFloat(ramVal) : null;
    data[i].ram = data[i].ramNum != null ? String(Math.round(data[i].ramNum * 10) / 10) : 'N/A';

    var disks = data[i].hdd;
    var diskStr = 'N/A';
    if (disks && Array.isArray(disks) && disks.length > 0) {
        var seen = {};
        var parts = [];
        for (var d = 0; d < disks.length; d++) {
            var dev = disks[d].device || '';
            if (!seen[dev]) {
                seen[dev] = true;
                parts.push(dev + ' ' + (disks[d].total || ''));
            }
        }
        diskStr = parts.join(', ');
    }
    data[i].hdd = diskStr;
}

buildHeader();
renderBody();
updateCount();

document.getElementById('loading').style.display = 'none';
document.getElementById('tableWrap').style.display = 'block';
</script>
{% endblock %}
